namespace sv_9287578664e948bb9a89eb40b4b938d2.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    DateTimeOffset Timestamp);

using sv_9287578664e948bb9a89eb40b4b938d2.Client.Models;

namespace sv_9287578664e948bb9a89eb40b4b938d2.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_9287578664e948bb9a89eb40b4b938d2.Client.Models;
using sv_9287578664e948bb9a89eb40b4b938d2.Client.Services;

namespace sv_9287578664e948bb9a89eb40b4b938d2.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Memphis, TN",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 24, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 19, 9, 0, 0, TimeSpan.Zero)),
                new("Arrived at sorting facility", new DateTimeOffset(2026, 5, 19, 14, 30, 0, TimeSpan.Zero)),
                new("Departed sorting facility", new DateTimeOffset(2026, 5, 20, 6, 0, 0, TimeSpan.Zero)),
                new("In transit to destination", new DateTimeOffset(2026, 5, 21, 8, 15, 0, TimeSpan.Zero))
            }),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "Seattle, WA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero)),
                new("In transit", new DateTimeOffset(2026, 5, 18, 7, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero)),
                new("Delivered — signed by J. Smith", new DateTimeOffset(2026, 5, 20, 11, 42, 0, TimeSpan.Zero))
            }),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 27, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Label created", new DateTimeOffset(2026, 5, 21, 15, 0, 0, TimeSpan.Zero))
            })
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_9287578664e948bb9a89eb40b4b938d2.Client.Models;

namespace sv_9287578664e948bb9a89eb40b4b938d2.Client.Services;

public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_9287578664e948bb9a89eb40b4b938d2.Client.Models
@using sv_9287578664e948bb9a89eb40b4b938d2.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Tracking History</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

